def parse_position(position_str):
    position = {}
    for row in range(8):
        for col in range(8):
            square = chr(col + 97) + str(8 - row)
            piece = position_str[row * 8 + col] if position_str[row * 8 + col] != '.' else ''
            position[square] = piece
    return position

