    for square in range(64):
        piece = board.piece_at(square)
        if piece:
            if piece.color == chess.WHITE:
                if piece.piece_type == chess.PAWN:
                    score += 1
                elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                    score += 3
                elif piece.piece_type == chess.ROOK:
                    score += 5
                elif piece.piece_type == chess.QUEEN:
                    score += 9
            else:
                if piece.piece_type == chess.PAWN:
                    score -= 1
                elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                    score -= 3
                elif piece.piece_type == chess.ROOK:
                    score -= 5
                elif piece.piece_type == chess.QUEEN:
                    score -= 9

    # Mobility evaluation
    white_moves = len(list(board.legal_moves))
    black_moves = len(list(board.generate_legal_moves()))
    score += white_moves - black_moves

    # King safety evaluation
    if board.is_check():
        if board.turn == chess.WHITE:
            score -= 2
        else:
            score += 2

    # Pawn structure evaluation
    pawns = board.pieces(chess.PAWN, chess.WHITE) | board.pieces(chess.PAWN, chess.BLACK)
    for pawn in pawns:
        if board.is_passed_pawn(pawn, chess.WHITE):
            score += 1
        elif board.is_passed_pawn(pawn, chess.BLACK):
